import { ImageResponse } from 'next/og'
import { type NextRequest } from 'next/server'

const CAPRASIMO_B64 = ''
const fontData: ArrayBuffer = Buffer.from(CAPRASIMO_B64, 'base64').buffer

export async function GET(request: NextRequest) {
  const { searchParams } = request.nextUrl
  const n = searchParams.get('n') ?? '001'
  const label = searchParams.get('label') ?? 'MESSY SORT'
  const detail = searchParams.get('detail') ?? ''
  const num = String(n).padStart(3, '0')

  return new ImageResponse(
    (
      <div style={{ width: '100%', height: '100%', display: 'flex', background: '#f3e9d6' }}>
        <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 160, background: '#2a1f15', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <span style={{ fontFamily: 'monospace', fontSize: 24, fontWeight: 700, letterSpacing: '0.15em', textTransform: 'uppercase', color: '#ffffff' }}>
            {`SORTL #${num}`}
          </span>
        </div>
        <div style={{ position: 'absolute', top: 265, left: 0, right: 0, display: 'flex', justifyContent: 'center' }}>
          <span style={{ fontSize: 42, fontFamily: 'monospace', textTransform: 'uppercase', letterSpacing: '0.12em', color: '#c45a3a' }}>
            {label}
          </span>
        </div>
        {detail && (
          <div style={{ position: 'absolute', top: 348, left: 0, right: 0, display: 'flex', justifyContent: 'center' }}>
            <span style={{ fontSize: 22, fontFamily: 'monospace', color: '#8a7355', letterSpacing: '0.06em' }}>
              {detail}
            </span>
          </div>
        )}
        <div style={{ position: 'absolute', bottom: 36, left: 0, right: 0, display: 'flex', justifyContent: 'center' }}>
          <span style={{ fontFamily: 'monospace', fontSize: 14, letterSpacing: '0.08em', color: 'rgba(42,31,21,0.45)' }}>
            sortl.stoop.games
          </span>
        </div>
      </div>
    ),
    {
      width: 1200,
      height: 630,
      fonts: [{ name: 'Caprasimo', data: fontData, weight: 400, style: 'normal' }],
    }
  )
}